import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { History, Clock, User, RotateCcw, Eye } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';

interface VersionHistoryItem {
  id: string;
  version: string;
  timestamp: Date;
  author: string;
  changes: string[];
  risksCount: number;
  locationsCount: number;
  workStationsCount: number;
}

interface VersionHistoryProps {
  companyId?: number;
  onRestore?: (version: VersionHistoryItem) => void;
}

export function VersionHistory({ companyId, onRestore }: VersionHistoryProps) {
  const [versions, setVersions] = useState<VersionHistoryItem[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    if (companyId) {
      loadVersionHistory();
    }
  }, [companyId]);

  const loadVersionHistory = async () => {
    setIsLoading(true);
    try {
      // Simulation de l'historique des versions
      const mockVersions: VersionHistoryItem[] = [
        {
          id: 'v1',
          version: '1.0.0',
          timestamp: new Date(Date.now() - 1000 * 60 * 30), // 30 minutes ago
          author: 'Utilisateur actuel',
          changes: ['Création du document', 'Ajout de 2 lieux', 'Ajout de 1 poste de travail'],
          risksCount: 12,
          locationsCount: 2,
          workStationsCount: 1
        },
        {
          id: 'v2',
          version: '1.1.0',
          timestamp: new Date(Date.now() - 1000 * 60 * 60 * 2), // 2 hours ago
          author: 'Utilisateur actuel',
          changes: ['Génération des risques automatique', 'Ajout de mesures de prévention'],
          risksCount: 18,
          locationsCount: 2,
          workStationsCount: 1
        },
        {
          id: 'v3',
          version: '1.2.0',
          timestamp: new Date(Date.now() - 1000 * 60 * 60 * 24), // 1 day ago
          author: 'Utilisateur actuel',
          changes: ['Ajout de suggestions IA', 'Analyse photo intégrée', 'Nouvelles mesures de prévention'],
          risksCount: 25,
          locationsCount: 3,
          workStationsCount: 2
        }
      ];

      setVersions(mockVersions);
    } catch (error) {
      console.error('Error loading version history:', error);
      toast({
        title: "Erreur",
        description: "Impossible de charger l'historique des versions",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleRestore = (version: VersionHistoryItem) => {
    if (onRestore) {
      onRestore(version);
      toast({
        title: "Version restaurée",
        description: `Le document a été restauré à la version ${version.version}`,
      });
    }
  };

  const handlePreview = (version: VersionHistoryItem) => {
    toast({
      title: "Aperçu de la version",
      description: `Affichage de la version ${version.version} (fonctionnalité à venir)`,
    });
  };

  if (!companyId) {
    return (
      <Card className="animate-fade-in">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <History className="h-5 w-5 text-gray-500" />
            Historique des versions
          </CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-muted-foreground">
            Créez d'abord une entreprise pour voir l'historique des versions
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="animate-fade-in">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <History className="h-5 w-5 text-blue-500" />
          Historique des versions
          <Badge variant="secondary">
            {versions.length} version{versions.length > 1 ? 's' : ''}
          </Badge>
        </CardTitle>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <div className="text-center py-4">
            <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-primary mx-auto mb-2"></div>
            <p className="text-sm text-muted-foreground">Chargement...</p>
          </div>
        ) : (
          <div className="space-y-4">
            {versions.map((version, index) => (
              <div key={version.id} className="relative">
                {index < versions.length - 1 && (
                  <div className="absolute left-4 top-12 w-0.5 h-full bg-border"></div>
                )}
                <div className="flex items-start gap-3">
                  <div className="flex-shrink-0 w-8 h-8 bg-primary/10 rounded-full flex items-center justify-center">
                    <Clock className="h-4 w-4 text-primary" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-1">
                      <div className="flex items-center gap-2">
                        <h4 className="font-medium text-sm">Version {version.version}</h4>
                        {index === 0 && (
                          <Badge variant="outline" className="text-xs">
                            Actuelle
                          </Badge>
                        )}
                      </div>
                      <div className="flex items-center gap-1">
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => handlePreview(version)}
                          className="h-7 px-2"
                        >
                          <Eye className="h-3 w-3" />
                        </Button>
                        {index > 0 && (
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => handleRestore(version)}
                            className="h-7 px-2"
                          >
                            <RotateCcw className="h-3 w-3" />
                          </Button>
                        )}
                      </div>
                    </div>
                    <div className="flex items-center gap-2 mb-2">
                      <div className="flex items-center gap-1">
                        <User className="h-3 w-3 text-muted-foreground" />
                        <span className="text-xs text-muted-foreground">{version.author}</span>
                      </div>
                      <span className="text-xs text-muted-foreground">
                        {format(version.timestamp, "dd MMM yyyy 'à' HH:mm", { locale: fr })}
                      </span>
                    </div>
                    <div className="space-y-1">
                      {version.changes.map((change, changeIndex) => (
                        <p key={changeIndex} className="text-xs text-muted-foreground">
                          • {change}
                        </p>
                      ))}
                    </div>
                    <div className="flex items-center gap-3 mt-2">
                      <Badge variant="outline" className="text-xs">
                        {version.risksCount} risques
                      </Badge>
                      <Badge variant="outline" className="text-xs">
                        {version.locationsCount} lieux
                      </Badge>
                      <Badge variant="outline" className="text-xs">
                        {version.workStationsCount} postes
                      </Badge>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

client/src/components/StepperDuerp.tsx.content:
import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { 
  Building, 
  MapPin, 
  FileText, 
  BarChart3, 
  Save, 
  ArrowLeft, 
  ArrowRight,
  CheckCircle 
} from 'lucide-react';

interface StepperDuerpProps {
  currentStep: number;
  totalSteps: number;
  onStepChange: (step: number) => void;
  onSave: () => void;
  isSaving?: boolean;
  completedSteps: number[];
}

const steps = [
  {
    id: 1,
    title: "Informations de la société",
    description: "Nom, adresse, secteur, employés",
    icon: Building
  },
  {
    id: 2,
    title: "Unités de travail",
    description: "Unités, postes et sites",
    icon: MapPin
  },
  {
    id: 3,
    title: "Tableau des risques",
    description: "Évaluation des risques professionnels",
    icon: FileText
  },
  {
    id: 4,
    title: "Analyse et graphiques",
    description: "Visualisation des risques",
    icon: BarChart3
  }
];

export default function StepperDuerp({ 
  currentStep, 
  totalSteps, 
  onStepChange, 
  onSave, 
  isSaving = false,
  completedSteps = []
}: StepperDuerpProps) {
  const progress = (currentStep / totalSteps) * 100;

  return (
    <Card className="mb-6">
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle className="text-xl">
            Générateur DUERP - Étape {currentStep} sur {totalSteps}
          </CardTitle>
          <Button
            onClick={onSave}
            disabled={isSaving}
            variant="outline"
            size="sm"
            className="flex items-center gap-2"
          >
            <Save className="h-4 w-4" />
            {isSaving ? 'Sauvegarde...' : 'Sauvegarder'}
          </Button>
        </div>
        <Progress value={progress} className="mt-2" />
      </CardHeader>
      <CardContent>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {steps.map((step) => {
            const isActive = step.id === currentStep;
            const isCompleted = completedSteps.includes(step.id);
            const Icon = step.icon;

            return (
              <div
                key={step.id}
                className={`
                  relative p-4 rounded-lg border-2 transition-all cursor-pointer
                  ${isActive 
                    ? 'border-primary bg-primary/5 shadow-sm' 
                    : isCompleted 
                      ? 'border-green-500 bg-green-50 dark:bg-green-900/20' 
                      : 'border-muted hover:border-muted-foreground/50'
                  }
                `}
                onClick={() => onStepChange(step.id)}
              >
                <div className="flex items-start gap-3">
                  <div className={`
                    p-2 rounded-full
                    ${isActive 
                      ? 'bg-primary text-primary-foreground' 
                      : isCompleted 
                        ? 'bg-green-500 text-white' 
                        : 'bg-muted'
                    }
                  `}>
                    {isCompleted ? (
                      <CheckCircle className="h-4 w-4" />
                    ) : (
                      <Icon className="h-4 w-4" />
                    )}
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-medium text-sm">{step.title}</h3>
                      {isCompleted && (
                        <Badge variant="secondary" className="text-xs">
                          Terminé
                        </Badge>
                      )}
                    </div>
                    <p className="text-xs text-muted-foreground">
                      {step.description}
                    </p>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="flex justify-between items-center mt-6">
          <Button
            onClick={() => onStepChange(Math.max(1, currentStep - 1))}
            disabled={currentStep === 1}
            variant="outline"
            size="sm"
          >
            <ArrowLeft className="h-4 w-4 mr-2" />
            Précédent
          </Button>

          <div className="text-sm text-muted-foreground">
            Étape {currentStep} sur {totalSteps}
          </div>

          <Button
            onClick={() => onStepChange(Math.min(totalSteps, currentStep + 1))}
            disabled={currentStep === totalSteps}
            size="sm"
          >
            Suivant
            <ArrowRight className="h-4 w-4 ml-2" />
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

