  background: linear-gradient(135deg, hsl(142, 71%, 95%) 0%, hsl(142, 71%, 90%) 100%);
  box-shadow: 0 2px 4px rgba(16, 185, 129, 0.1);
}
.risk-medium { 
  @apply bg-amber-100 text-amber-800 border border-amber-200 dark:bg-amber-900/20 dark:text-amber-300 dark:border-amber-800;
  background: linear-gradient(135deg, hsl(43, 96%, 95%) 0%, hsl(43, 96%, 90%) 100%);
