              children: [new TextRun({ text: risk.measures || 'À définir', size: 24, font: "Arial" })]
            })]
          })
        ]
      }))
    ];

    duerpElements.push(
      new Table({
        rows: tableRows,
        width: { size: 100, type: WidthType.PERCENTAGE }
      }),
